/**
 * Config merger for TestDino CLI
 * Merges configuration from multiple sources with proper precedence
 */

import { randomUUID } from 'crypto';
import type { CliOptions, MergedConfig, ConfigFileContent } from './types.js';
import type { TestdinoConfig } from '../types/index.js';
import type { CoverageConfig } from '../code-coverage/types.js';
import { TokenMissingError, InvalidServerUrlError } from './errors.js';

/**
 * Config sources for merging
 */
export interface ConfigSources {
  env?: Partial<TestdinoConfig>;
  playwrightConfig?: TestdinoConfig;
  testdinoConfig?: ConfigFileContent;
  cliOptions?: CliOptions;
}

/**
 * Config merger class
 * Merges configs with priority: CLI > testdino.config > playwright.config > env vars
 */
export class ConfigMerger {
  private static readonly DEFAULT_SERVER_URL = 'https://api.testdino.com';

  /**
   * Merge configurations from all sources
   * Priority (highest to lowest):
   * 1. CLI flags
   * 2. testdino.config.[ts|js]
   * 3. playwright.config reporter options
   * 4. Environment variables
   */
  merge(sources: ConfigSources): MergedConfig {
    const { env = {}, playwrightConfig = {}, testdinoConfig = {}, cliOptions = {} } = sources;

    // Merge token (required field)
    const token = this.selectValue(cliOptions.token, testdinoConfig.token, playwrightConfig.token, env.token);

    // Merge serverUrl with default fallback
    const serverUrl =
      this.selectValue(cliOptions.serverUrl, testdinoConfig.serverUrl, playwrightConfig.serverUrl, env.serverUrl) ||
      ConfigMerger.DEFAULT_SERVER_URL;

    // Merge ciRunId (auto-generate if not provided)
    const ciRunId =
      this.selectValue(cliOptions.ciRunId, testdinoConfig.ciRunId, playwrightConfig.ciRunId) || this.generateCiRunId();

    // Merge debug flag (default to false)
    const debug = this.selectValue(cliOptions.debug, testdinoConfig.debug, playwrightConfig.debug, env.debug) ?? false;

    // Merge artifacts flag (default to true)
    // CLI --no-artifacts sets artifacts=false via Commander's boolean negation
    const artifacts =
      cliOptions.artifacts !== undefined
        ? cliOptions.artifacts
        : (this.selectValue(testdinoConfig.artifacts, playwrightConfig.artifacts) ?? true);

    // Merge coverage configuration
    // CLI --coverage only toggles enabled; other fields come from config files
    const coverage = this.mergeCoverageConfig(cliOptions.coverage, testdinoConfig.coverage, playwrightConfig.coverage);

    const mergedConfig: MergedConfig = {
      token,
      serverUrl,
      ciRunId,
      debug,
      artifacts,
      ...(coverage ? { coverage } : {}),
    };

    // Validate the merged config
    this.validate(mergedConfig);

    return mergedConfig;
  }

  /**
   * Merge coverage configuration from CLI flag and config files.
   * CLI --coverage only toggles enabled; other fields come from config files.
   */
  private mergeCoverageConfig(
    cliCoverage: boolean | undefined,
    testdinoCoverage: CoverageConfig | undefined,
    playwrightCoverage: CoverageConfig | undefined
  ): CoverageConfig | undefined {
    const baseConfig = testdinoCoverage ?? playwrightCoverage;

    if (!baseConfig && cliCoverage === undefined) return undefined;

    if (cliCoverage !== undefined) {
      return { ...(baseConfig || { enabled: false }), enabled: cliCoverage };
    }

    return baseConfig;
  }

  /**
   * Select first non-undefined value from arguments
   */
  private selectValue<T>(...values: (T | undefined)[]): T | undefined {
    return values.find((value) => value !== undefined && value !== null);
  }

  /**
   * Generate a unique CI run ID
   */
  private generateCiRunId(): string {
    return `run-${randomUUID()}`;
  }

  /**
   * Validate merged configuration
   */
  private validate(config: MergedConfig): void {
    // Token is required - throw specific error
    if (!config.token || typeof config.token !== 'string' || config.token.trim().length === 0) {
      throw new TokenMissingError();
    }

    // ServerUrl must be valid if provided - throw specific error
    if (config.serverUrl) {
      if (typeof config.serverUrl !== 'string' || !this.isValidUrl(config.serverUrl)) {
        throw new InvalidServerUrlError(config.serverUrl);
      }
    }

    // Note: ciRunId and debug validations removed as they are handled internally
    // and don't need user-facing error messages
  }

  /**
   * Check if string is a valid URL
   */
  private isValidUrl(urlString: string): boolean {
    try {
      const url = new URL(urlString);
      return url.protocol === 'http:' || url.protocol === 'https:';
    } catch {
      return false;
    }
  }

  /**
   * Get environment variables as config
   */
  static getEnvConfig(): Partial<TestdinoConfig> {
    const config: Partial<TestdinoConfig> = {};

    if (process.env.TESTDINO_TOKEN) {
      config.token = process.env.TESTDINO_TOKEN;
    }

    if (process.env.TESTDINO_SERVER_URL) {
      config.serverUrl = process.env.TESTDINO_SERVER_URL;
    }

    if (process.env.TESTDINO_DEBUG) {
      config.debug = process.env.TESTDINO_DEBUG === 'true' || process.env.TESTDINO_DEBUG === '1';
    }

    return config;
  }
}
