/**
 * Shared utility functions
 */

import { relative } from 'path';

/**
 * Normalize file path to repo-root-relative.
 * Ensures consistent paths across different machines and shards.
 */
export function normalizePath(filePath: string, rootDir?: string): string {
  if (rootDir) {
    // Strip trailing slash so boundary check uses consistent form
    const root = rootDir.endsWith('/') ? rootDir.slice(0, -1) : rootDir;
    if (filePath === root || filePath.startsWith(`${root}/`)) {
      return relative(root, filePath);
    }
  }
  return filePath;
}

/**
 * Sleep utility for retry delays
 */
export function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Check if debug mode is enabled (standardized check)
 */
export function isDebugEnabled(): boolean {
  return process.env.TESTDINO_DEBUG === 'true' || process.env.TESTDINO_DEBUG === '1' || process.env.DEBUG === 'true';
}
