/**
 * Argument filter for TestDino CLI
 * Filters out TestDino-specific flags from arguments before passing to Playwright
 */

/**
 * TestDino-specific flags that should be removed before passing to Playwright
 */
const TESTDINO_FLAGS = ['--token', '-t', '--ci-run-id', '--server-url', '--debug', '--no-artifacts', '--coverage'];

/**
 * Flags that take a value (not boolean flags)
 */
const FLAGS_WITH_VALUES = ['--token', '-t', '--ci-run-id', '--server-url'];

/**
 * Argument filter class
 */
export class ArgFilter {
  /**
   * Filter TestDino-specific arguments from the argument list
   * Removes both flags and their values
   *
   * @param args - Raw command line arguments
   * @returns Filtered arguments safe to pass to Playwright
   */
  filter(args: string[]): string[] {
    const result: string[] = [];
    let skipNext = false;

    for (let i = 0; i < args.length; i++) {
      const arg = args[i];

      // Skip this arg if previous flag indicated we should
      if (skipNext) {
        skipNext = false;
        continue;
      }

      // Check if this is a TestDino flag
      if (this.isTestdinoFlag(arg)) {
        // Check if it's a flag with value (not using = syntax)
        if (this.isFlagWithValue(arg) && !arg.includes('=')) {
          // Skip the next argument (the value)
          skipNext = true;
        }
        // Skip this flag
        continue;
      }

      // Check if this is a TestDino flag with = syntax (e.g., --token=value)
      if (this.isTestdinoFlagWithEquals(arg)) {
        // Skip this entire argument
        continue;
      }

      // Keep this argument
      result.push(arg);
    }

    return result;
  }

  /**
   * Check if argument is a TestDino flag
   */
  private isTestdinoFlag(arg: string): boolean {
    // Extract flag name (before = if present)
    const flagName = arg.split('=')[0];
    return TESTDINO_FLAGS.includes(flagName);
  }

  /**
   * Check if argument is a TestDino flag with = syntax
   */
  private isTestdinoFlagWithEquals(arg: string): boolean {
    if (!arg.includes('=')) {
      return false;
    }
    const flagName = arg.split('=')[0];
    return TESTDINO_FLAGS.includes(flagName);
  }

  /**
   * Check if flag takes a value
   */
  private isFlagWithValue(arg: string): boolean {
    const flagName = arg.split('=')[0];
    return FLAGS_WITH_VALUES.includes(flagName);
  }

  /**
   * Get list of TestDino flags (for reference/testing)
   */
  static getTestdinoFlags(): string[] {
    return [...TESTDINO_FLAGS];
  }
}
