/**
 * CLI logger with colors and formatting
 * Provides consistent, user-friendly output
 */

import chalk from 'chalk';
import { isDebugEnabled } from '../utils/index.js';

/**
 * Log levels
 */
export enum LogLevel {
  ERROR = 'error',
  WARN = 'warn',
  INFO = 'info',
  SUCCESS = 'success',
  DEBUG = 'debug',
}

/**
 * CLI Logger class
 */
export class Logger {
  private debugEnabled: boolean;

  constructor(debugEnabled = false) {
    this.debugEnabled = debugEnabled;
  }

  /**
   * Enable or disable debug logging
   */
  setDebug(enabled: boolean): void {
    this.debugEnabled = enabled;
  }

  /**
   * Log error message
   */
  error(message: string, error?: Error): void {
    console.error(chalk.red(`\n✖ Error: ${message}`));

    if (error && this.debugEnabled) {
      console.error(chalk.dim('\nStack trace:'));
      console.error(chalk.dim(error.stack || error.message));
    }
  }

  /**
   * Log warning message
   */
  warn(message: string): void {
    console.warn(chalk.yellow(`⚠️  Warning: ${message}`));
  }

  /**
   * Log info message
   */
  info(message: string): void {
    console.log(chalk.blue(`ℹ️  ${message}`));
  }

  /**
   * Log success message
   */
  success(message: string): void {
    console.log(chalk.green(`✓ ${message}`));
  }

  /**
   * Log debug message (only if debug is enabled)
   */
  debug(message: string): void {
    if (this.debugEnabled) {
      console.log(chalk.dim(`[DEBUG] ${message}`));
    }
  }

  /**
   * Log a blank line
   */
  newline(): void {
    console.log();
  }

  /**
   * Log a section header
   */
  section(title: string): void {
    console.log(chalk.bold.cyan(`\n${title}`));
  }

  /**
   * Log a list item
   */
  listItem(text: string): void {
    console.log(`  • ${text}`);
  }

  /**
   * Log code/command
   */
  code(text: string): void {
    console.log(chalk.gray(`  ${text}`));
  }

  /**
   * Format error for display
   */
  formatError(error: Error): string {
    if (this.debugEnabled && error.stack) {
      return error.stack;
    }
    return error.message;
  }

  /**
   * Log TestDino CLI banner
   */
  banner(version: string): void {
    console.log(
      chalk.cyan(`
╔═══════════════════════════════════════════════════════════╗
║                                                           ║
║   ${chalk.bold('TestDino Playwright')} v${version.padEnd(36)}║
║   ${chalk.dim('https://testdino.com')}                                  ║
║                                                           ║
╚═══════════════════════════════════════════════════════════╝
`)
    );
  }
}

/**
 * Default logger instance
 */
export const logger = new Logger(isDebugEnabled());
