/**
 * Config detector for TestDino CLI
 * Detects and extracts TestdinoReporter configuration from playwright.config.[ts|js]
 */

import { existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import jiti from 'jiti';
import type { TestdinoConfig } from '../types/index.js';
import type { CoverageConfig } from '../code-coverage/types.js';
import { ConfigSyntaxError } from './errors.js';

const PLAYWRIGHT_CONFIG_FILENAMES = ['playwright.config.ts', 'playwright.config.js'];
const TESTDINO_REPORTER_NAMES = ['@testdino/playwright', 'testdino-playwright', 'TestdinoReporter'];

/**
 * Result of config detection
 */
export interface ConfigDetectionResult {
  hasReporter: boolean;
  options?: TestdinoConfig;
  configPath?: string;
}

/**
 * Playwright config structure (simplified)
 */
interface PlaywrightConfig {
  reporter?: ReporterConfig;
  [key: string]: unknown;
}

/**
 * Reporter configuration can be:
 * - string: 'html'
 * - [string]: ['html']
 * - [string, options]: ['html', { outputDir: 'report' }]
 * - Array of above
 */
type ReporterConfig = string | [string, Record<string, unknown>?] | Array<string | [string, Record<string, unknown>?]>;

/**
 * Check if a value is a valid coverage threshold (finite number in range 0–100).
 */
function isValidThreshold(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value) && value >= 0 && value <= 100;
}

/**
 * Config detector class
 */
export class ConfigDetector {
  private cwd: string;

  constructor(cwd: string = process.cwd()) {
    this.cwd = cwd;
  }

  /**
   * Detect TestdinoReporter in Playwright config
   */
  async detect(): Promise<ConfigDetectionResult> {
    const configPath = this.findPlaywrightConfig();

    if (!configPath) {
      return { hasReporter: false };
    }

    try {
      const config = this.loadPlaywrightConfig(configPath);
      const result = this.extractTestdinoReporter(config);

      return {
        ...result,
        configPath,
      };
    } catch (error) {
      throw new ConfigSyntaxError(configPath, error instanceof Error ? error : new Error(String(error)));
    }
  }

  /**
   * Find playwright.config.[ts|js] in current directory
   */
  private findPlaywrightConfig(): string | undefined {
    for (const filename of PLAYWRIGHT_CONFIG_FILENAMES) {
      const configPath = join(this.cwd, filename);
      if (existsSync(configPath)) {
        return configPath;
      }
    }
    return undefined;
  }

  /**
   * Load and parse Playwright config using jiti
   */
  private loadPlaywrightConfig(configPath: string): PlaywrightConfig {
    const jitiLoader = jiti(dirname(configPath), {
      interopDefault: true,
      cache: false,
      extensions: ['.ts', '.js'],
    });

    let loaded: unknown;
    try {
      const resolved = jitiLoader.esmResolve(configPath, { try: true });
      if (!resolved) {
        throw new Error(`Could not resolve Playwright config: ${configPath}`);
      }

      const resolvedPath = typeof resolved === 'string' ? resolved : fileURLToPath(resolved);
      loaded = jitiLoader(resolvedPath);
    } catch (error) {
      throw new Error(`Syntax error: ${error instanceof Error ? error.message : String(error)}`);
    }

    // Extract config from default export or direct export
    let config: unknown;
    if (loaded && typeof loaded === 'object' && '__esModule' in loaded) {
      config = (loaded as Record<string, unknown>).default;
    } else if (loaded && typeof loaded === 'object' && 'default' in loaded) {
      config = (loaded as Record<string, unknown>).default;
    } else {
      config = loaded;
    }

    // Handle function configs (Playwright supports this)
    if (typeof config === 'function') {
      try {
        config = config();
      } catch (error) {
        throw new Error(`Error executing config function: ${error instanceof Error ? error.message : String(error)}`);
      }
    }

    // Validate config structure
    if (!config || typeof config !== 'object') {
      throw new Error('Playwright config must be an object');
    }

    return config as PlaywrightConfig;
  }

  /**
   * Extract TestdinoReporter configuration from Playwright config
   */
  private extractTestdinoReporter(config: PlaywrightConfig): Omit<ConfigDetectionResult, 'configPath'> {
    const { reporter } = config;

    if (!reporter) {
      return { hasReporter: false };
    }

    // Handle single reporter as string
    if (typeof reporter === 'string') {
      if (this.isTestdinoReporter(reporter)) {
        return { hasReporter: true, options: {} };
      }
      return { hasReporter: false };
    }

    // Handle single reporter as tuple [name, options]
    if (Array.isArray(reporter) && reporter.length > 0) {
      // Check if it's a single reporter tuple: ['reporter-name', { options }]
      if (typeof reporter[0] === 'string') {
        const [name, options] = reporter as [string, Record<string, unknown>?];
        if (this.isTestdinoReporter(name)) {
          return {
            hasReporter: true,
            options: this.extractOptions(options),
          };
        }
        // If first element is string but not TestDino, might be array of reporters
        // Fall through to array handling
      }

      // Handle array of reporters
      for (const item of reporter) {
        if (typeof item === 'string') {
          if (this.isTestdinoReporter(item)) {
            return { hasReporter: true, options: {} };
          }
        } else if (Array.isArray(item) && item.length > 0) {
          const [name, options] = item as [string, Record<string, unknown>?];
          if (this.isTestdinoReporter(name)) {
            return {
              hasReporter: true,
              options: this.extractOptions(options),
            };
          }
        }
      }
    }

    return { hasReporter: false };
  }

  /**
   * Check if reporter name matches TestdinoReporter
   */
  private isTestdinoReporter(name: string): boolean {
    return TESTDINO_REPORTER_NAMES.some((testdinoName) => name === testdinoName || name.includes(testdinoName));
  }

  /**
   * Extract and validate TestdinoConfig options
   */
  private extractOptions(options?: Record<string, unknown>): TestdinoConfig {
    if (!options || typeof options !== 'object') {
      return {};
    }

    const config: TestdinoConfig = {};

    if ('token' in options && typeof options.token === 'string') {
      config.token = options.token;
    }

    if ('serverUrl' in options && typeof options.serverUrl === 'string') {
      config.serverUrl = options.serverUrl;
    }

    if ('ciRunId' in options && typeof options.ciRunId === 'string') {
      config.ciRunId = options.ciRunId;
    }

    if ('debug' in options && typeof options.debug === 'boolean') {
      config.debug = options.debug;
    }

    if ('coverage' in options && typeof options.coverage === 'object' && options.coverage !== null) {
      config.coverage = this.extractCoverageConfig(options.coverage as Record<string, unknown>);
    }

    return config;
  }

  /**
   * Extract and validate CoverageConfig from reporter options
   */
  private extractCoverageConfig(raw: Record<string, unknown>): CoverageConfig {
    const config: CoverageConfig = {
      enabled: typeof raw.enabled === 'boolean' ? raw.enabled : false,
    };

    if (Array.isArray(raw.include)) {
      config.include = raw.include.filter((p): p is string => typeof p === 'string');
    }

    if (Array.isArray(raw.exclude)) {
      config.exclude = raw.exclude.filter((p): p is string => typeof p === 'string');
    }

    if (typeof raw.thresholds === 'object' && raw.thresholds !== null) {
      const t = raw.thresholds as Record<string, unknown>;
      config.thresholds = {};
      if (isValidThreshold(t.statements)) config.thresholds.statements = t.statements as number;
      if (isValidThreshold(t.branches)) config.thresholds.branches = t.branches as number;
      if (isValidThreshold(t.functions)) config.thresholds.functions = t.functions as number;
      if (isValidThreshold(t.lines)) config.thresholds.lines = t.lines as number;
    }

    return config;
  }
}
