/**
 * Playwright spawner for TestDino CLI
 * Spawns Playwright test process with TestDino configuration
 */

import { execa, type ExecaError } from 'execa';
import type { MergedConfig } from './types.js';
import { Logger } from './logger.js';

/**
 * Spawn options
 */
export interface PlaywrightSpawnOptions {
  args: string[];
  tempConfigPath: string;
  config: MergedConfig;
  cwd?: string;
}

/**
 * Spawn result
 */
export interface PlaywrightSpawnResult {
  exitCode: number;
  success: boolean;
}

/**
 * Playwright spawner class
 */
export class PlaywrightSpawner {
  private logger: Logger;

  constructor(logger?: Logger) {
    this.logger = logger ?? new Logger();
  }

  /**
   * Spawn Playwright test process
   * @param options - Spawn options
   * @returns Spawn result with exit code
   */
  async spawn(options: PlaywrightSpawnOptions): Promise<PlaywrightSpawnResult> {
    const { args, tempConfigPath, config, cwd = process.cwd() } = options;

    try {
      // Build environment variables
      const env = {
        ...process.env,
        TESTDINO_CLI_CONFIG_PATH: tempConfigPath,
        TESTDINO_TOKEN: config.token,
        TESTDINO_SERVER_URL: config.serverUrl,
        TESTDINO_CI_RUN_ID: config.ciRunId,
        TESTDINO_DEBUG: config.debug ? 'true' : 'false',
      };

      // Build Playwright arguments with injected reporter
      const playwrightArgs = ['playwright', 'test', '--reporter', '@testdino/playwright', ...args];

      // Spawn Playwright with execa
      const result = await execa('npx', playwrightArgs, {
        stdio: 'inherit', // Forward stdout/stderr in real-time
        cwd,
        env,
        reject: false, // Don't throw on non-zero exit codes
      });

      const exitCode = result.exitCode ?? 0;

      return {
        exitCode,
        success: exitCode === 0,
      };
    } catch (error) {
      // Handle spawn errors (e.g., Playwright not installed, npx not found)
      return this.handleSpawnError(error);
    }
  }

  /**
   * Handle spawn errors
   */
  private handleSpawnError(error: unknown): PlaywrightSpawnResult {
    const execaError = error as ExecaError;

    // Check if it's a command not found error
    if (execaError.code === 'ENOENT') {
      this.logger.error('Failed to spawn Playwright');
      this.logger.newline();
      this.logger.info('Playwright is not installed or npx is not available.');
      this.logger.newline();
      this.logger.section('To install Playwright:');
      this.logger.code('npm install -D @playwright/test');
      this.logger.code('npx playwright install');
      return {
        exitCode: 1,
        success: false,
      };
    }

    // Check if it's a permission error
    if (execaError.code === 'EACCES') {
      this.logger.error('Permission denied when trying to spawn Playwright');
      this.logger.newline();
      this.logger.info('Please check file permissions and try again.');
      return {
        exitCode: 1,
        success: false,
      };
    }

    // Generic error
    this.logger.error('Failed to spawn Playwright');
    this.logger.newline();
    this.logger.info(`Error: ${execaError.message || String(error)}`);
    return {
      exitCode: 1,
      success: false,
    };
  }
}
