/**
 * Config file loader for TestDino CLI
 * Searches for testdino.config.[ts|js] up the directory tree
 */

import { existsSync, statSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import jiti from 'jiti';
import type { ConfigFileContent } from './types.js';
import { ConfigSyntaxError } from './errors.js';

const CONFIG_FILENAMES = ['testdino.config.ts', 'testdino.config.js'];

/**
 * Result of config loading
 */
export interface ConfigLoadResult {
  config: ConfigFileContent;
  configPath?: string;
}

/**
 * Config loader class
 */
export class ConfigLoader {
  private cwd: string;

  constructor(cwd: string = process.cwd()) {
    this.cwd = cwd;
  }

  /**
   * Load config file from current directory or parent directories
   */
  async load(): Promise<ConfigLoadResult> {
    const configPath = this.findConfigFile();

    if (!configPath) {
      return { config: {} };
    }

    try {
      const config = this.loadConfigFile(configPath);
      return { config, configPath };
    } catch (error) {
      throw new ConfigSyntaxError(configPath, error instanceof Error ? error : new Error(String(error)));
    }
  }

  /**
   * Find config file by searching up directory tree
   * Stops at .git directory
   */
  private findConfigFile(): string | undefined {
    let currentDir = this.cwd;

    while (true) {
      // Check for config files in current directory
      for (const filename of CONFIG_FILENAMES) {
        const configPath = join(currentDir, filename);
        if (existsSync(configPath)) {
          return configPath;
        }
      }

      // Check if we've reached .git directory
      const gitDir = join(currentDir, '.git');
      if (existsSync(gitDir) && statSync(gitDir).isDirectory()) {
        // Check one more time in the git root directory
        for (const filename of CONFIG_FILENAMES) {
          const configPath = join(currentDir, filename);
          if (existsSync(configPath)) {
            return configPath;
          }
        }
        // Stop at git root
        break;
      }

      // Move to parent directory
      const parentDir = dirname(currentDir);

      // Stop if we've reached the root
      if (parentDir === currentDir) {
        break;
      }

      currentDir = parentDir;
    }

    return undefined;
  }

  /**
   * Load and parse config file using jiti
   */
  private loadConfigFile(configPath: string): ConfigFileContent {
    const jitiLoader = jiti(dirname(configPath), {
      interopDefault: true,
      cache: false,
      extensions: ['.ts', '.js'],
    });

    let loaded: unknown;
    try {
      // Use jiti's esmResolve to handle both ESM and CommonJS
      const resolved = jitiLoader.esmResolve(configPath, { try: true });
      if (!resolved) {
        throw new Error(`Could not resolve config file: ${configPath}`);
      }

      const resolvedPath = typeof resolved === 'string' ? resolved : fileURLToPath(resolved);
      loaded = jitiLoader(resolvedPath);
    } catch (error) {
      throw new Error(`Syntax error: ${error instanceof Error ? error.message : String(error)}`);
    }

    // Extract config from default export or direct export
    // Handle __esModule pattern from jiti
    let config: unknown;
    if (loaded && typeof loaded === 'object' && '__esModule' in loaded) {
      config = (loaded as Record<string, unknown>).default;
    } else if (loaded && typeof loaded === 'object' && 'default' in loaded) {
      // Handle case where jiti returns { default: value } without __esModule
      config = (loaded as Record<string, unknown>).default;
    } else {
      config = loaded;
    }

    // Handle null/undefined from default export
    if (config === null || config === undefined) {
      return {};
    }

    // Handle function configs
    if (typeof config === 'function') {
      try {
        config = config();
      } catch (error) {
        throw new Error(`Error executing config function: ${error instanceof Error ? error.message : String(error)}`);
      }

      // Don't support async configs
      if (config instanceof Promise) {
        throw new Error('Async config functions are not supported');
      }

      // Handle null/undefined from function
      if (config === null || config === undefined) {
        return {};
      }
    }

    // Validate config structure
    if (config && typeof config !== 'object') {
      throw new Error('Config must be an object');
    }

    return config ?? {};
  }
}
