/**
 * Temp config file manager for TestDino CLI
 * Creates and manages temporary configuration files
 */

import { writeFileSync, unlinkSync, existsSync } from 'fs';
import { join } from 'path';
import { tmpdir } from 'os';
import { randomUUID } from 'crypto';
import type { MergedConfig, TempConfigInfo } from './types.js';
import { Logger } from './logger.js';

/**
 * Temp config manager class
 */
export class TempConfigManager {
  private tempFiles: Set<string> = new Set();
  private cleanupHandlersRegistered = false;
  private exitHandler?: () => void;
  private sigintHandler?: () => void;
  private sigtermHandler?: () => void;
  private uncaughtExceptionHandler?: (error: Error) => void;
  private unhandledRejectionHandler?: (reason: unknown) => void;
  private logger: Logger;

  constructor(logger?: Logger) {
    this.logger = logger ?? new Logger();
  }

  /**
   * Create a temporary config file with the merged configuration
   * @param config - Merged configuration to write
   * @returns Temp config info with path and config
   */
  create(config: MergedConfig): TempConfigInfo {
    const tempPath = this.generateTempPath();

    try {
      // Write config as JSON to temp file
      const configJson = JSON.stringify(config, null, 2);
      writeFileSync(tempPath, configJson, 'utf-8');

      // Track this file for cleanup
      this.tempFiles.add(tempPath);

      // Register cleanup handlers on first file creation
      if (!this.cleanupHandlersRegistered) {
        this.registerCleanupHandlers();
        this.cleanupHandlersRegistered = true;
      }

      return {
        path: tempPath,
        config,
      };
    } catch (error) {
      throw new Error(
        `Failed to create temp config file: ${tempPath}\n${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Clean up a specific temp config file
   * @param tempPath - Path to temp file to clean up
   */
  cleanup(tempPath: string): void {
    try {
      if (existsSync(tempPath)) {
        unlinkSync(tempPath);
      }
      this.tempFiles.delete(tempPath);
    } catch {
      // Log error but don't throw - cleanup should be best-effort
      this.logger.warn(`Failed to cleanup temp file: ${tempPath}`);
    }
  }

  /**
   * Clean up all tracked temp files
   */
  cleanupAll(): void {
    for (const tempPath of this.tempFiles) {
      this.cleanup(tempPath);
    }
    this.tempFiles.clear();
  }

  /**
   * Remove all event handlers (for testing)
   */
  removeHandlers(): void {
    if (this.exitHandler) {
      process.removeListener('exit', this.exitHandler);
    }
    if (this.sigintHandler) {
      process.removeListener('SIGINT', this.sigintHandler);
    }
    if (this.sigtermHandler) {
      process.removeListener('SIGTERM', this.sigtermHandler);
    }
    if (this.uncaughtExceptionHandler) {
      process.removeListener('uncaughtException', this.uncaughtExceptionHandler);
    }
    if (this.unhandledRejectionHandler) {
      process.removeListener('unhandledRejection', this.unhandledRejectionHandler);
    }
    this.cleanupHandlersRegistered = false;
  }

  /**
   * Generate unique temp file path
   */
  private generateTempPath(): string {
    const filename = `testdino-config-${randomUUID()}.json`;
    return join(tmpdir(), filename);
  }

  /**
   * Register cleanup handlers for process exit and signals
   */
  private registerCleanupHandlers(): void {
    // Normal exit
    this.exitHandler = () => {
      this.cleanupAll();
    };
    process.on('exit', this.exitHandler);

    // SIGINT (Ctrl+C)
    this.sigintHandler = () => {
      // Remove handler to prevent duplicate calls on repeated Ctrl+C
      if (this.sigintHandler) {
        process.removeListener('SIGINT', this.sigintHandler);
      }
      // Don't call cleanupAll() or process.exit() here.
      // Let the spawned Playwright process handle the signal and exit naturally.
      // The reporter needs time to send the run:end event with status='interrupted'.
      // Cleanup will happen in TestCommand's finally block after the child exits.
    };
    process.on('SIGINT', this.sigintHandler);

    // SIGTERM
    this.sigtermHandler = () => {
      // Remove handler to prevent duplicate calls
      if (this.sigtermHandler) {
        process.removeListener('SIGTERM', this.sigtermHandler);
      }
      // Don't call cleanupAll() or process.exit() - same reasoning as SIGINT
    };
    process.on('SIGTERM', this.sigtermHandler);

    // Uncaught exceptions
    this.uncaughtExceptionHandler = (error: Error) => {
      this.logger.error('Uncaught exception', error);
      this.cleanupAll();
      process.exit(1);
    };
    process.on('uncaughtException', this.uncaughtExceptionHandler);

    // Unhandled promise rejections
    this.unhandledRejectionHandler = (reason: unknown) => {
      this.logger.error('Unhandled rejection', reason instanceof Error ? reason : undefined);
      this.cleanupAll();
      process.exit(1);
    };
    process.on('unhandledRejection', this.unhandledRejectionHandler);
  }

  /**
   * Get list of tracked temp files (for testing)
   */
  getTempFiles(): string[] {
    return Array.from(this.tempFiles);
  }
}
