/**
 * Test command for TestDino CLI
 * Orchestrates all CLI components to run Playwright tests with TestDino reporter
 */

import { ConfigLoader } from '../config-loader.js';
import { ConfigDetector } from '../config-detector.js';
import { ConfigMerger } from '../config-merger.js';
import { ArgFilter } from '../arg-filter.js';
import { TempConfigManager } from '../temp-config.js';
import { PlaywrightSpawner } from '../playwright-spawner.js';
import { Logger } from '../logger.js';
import type { CliOptions } from '../types.js';
import type { PlaywrightSpawnResult } from '../playwright-spawner.js';

/**
 * Test command class
 * Orchestrates the full flow of running Playwright tests with TestDino
 */
export class TestCommand {
  private configLoader: ConfigLoader;
  private configDetector: ConfigDetector;
  private configMerger: ConfigMerger;
  private argFilter: ArgFilter;
  private tempConfigManager: TempConfigManager;
  private playwrightSpawner: PlaywrightSpawner;

  constructor(
    configLoader?: ConfigLoader,
    configDetector?: ConfigDetector,
    configMerger?: ConfigMerger,
    argFilter?: ArgFilter,
    tempConfigManager?: TempConfigManager,
    playwrightSpawner?: PlaywrightSpawner,
    logger?: Logger
  ) {
    this.configLoader = configLoader || new ConfigLoader();
    this.configDetector = configDetector || new ConfigDetector();
    this.configMerger = configMerger || new ConfigMerger();
    this.argFilter = argFilter || new ArgFilter();
    this.tempConfigManager = tempConfigManager || new TempConfigManager(logger);
    this.playwrightSpawner = playwrightSpawner || new PlaywrightSpawner(logger);
  }

  /**
   * Execute the test command
   * @param options - CLI options from commander
   * @param args - Remaining arguments to pass to Playwright
   * @returns Spawn result with exit code
   */
  async execute(options: CliOptions, args: string[]): Promise<PlaywrightSpawnResult> {
    let tempConfigPath: string | undefined;

    try {
      // 1. Load testdino.config.[ts|js]
      const testdinoConfigResult = await this.configLoader.load();

      // 2. Detect playwright.config.[ts|js] and TestdinoReporter
      const playwrightConfigResult = await this.configDetector.detect();

      // 3. Get environment variables
      const envConfig = ConfigMerger.getEnvConfig();

      // 4. Merge all configs with proper priority
      const mergedConfig = this.configMerger.merge({
        env: envConfig,
        playwrightConfig: playwrightConfigResult.options,
        testdinoConfig: testdinoConfigResult.config,
        cliOptions: options,
      });

      // 5. Create temp config file
      const tempConfigInfo = this.tempConfigManager.create(mergedConfig);
      tempConfigPath = tempConfigInfo.path;

      // 6. Filter TestDino-specific arguments
      const filteredArgs = this.argFilter.filter(args);

      // 7. Spawn Playwright with filtered args and config
      const result = await this.playwrightSpawner.spawn({
        args: filteredArgs,
        tempConfigPath,
        config: mergedConfig,
      });

      return result;
    } finally {
      // 8. Always cleanup temp config file
      if (tempConfigPath) {
        this.tempConfigManager.cleanup(tempConfigPath);
      }
    }
  }
}
