#!/usr/bin/env node

/**
 * TestDino Playwright CLI
 * Main entry point for the tdpw command
 */

import { Command } from 'commander';
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { TestCommand } from './commands/test.js';
import { Logger } from './logger.js';
import { TestDinoError } from './errors.js';
import { isDebugEnabled } from '../utils/index.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

/**
 * Get package version
 */
function getVersion(): string {
  try {
    // In built dist, package.json is two levels up
    const packagePath = join(__dirname, '../../package.json');
    const packageJson = JSON.parse(readFileSync(packagePath, 'utf-8'));
    return packageJson.version;
  } catch {
    return '0.0.0';
  }
}

// Logger instance created at program start, debug enabled via env vars initially
const logger = new Logger(isDebugEnabled());

/**
 * Build the CLI program
 */
function buildProgram(): Command {
  const program = new Command()
    .name('tdpw')
    .description('Run Playwright tests with TestDino reporting')
    .version(getVersion(), '-v, --version', 'Output the current version')
    .helpOption('-h, --help', 'Display help for command');

  // Test command
  program
    .command('test')
    .description('Run Playwright tests with TestDino reporter')
    .option('-t, --token <token>', 'TestDino authentication token')
    .option('--ci-run-id <id>', 'CI run ID for grouping test runs')
    .option('--server-url <url>', 'TestDino server URL')
    .option('--debug', 'Enable debug logging')
    .option('--no-artifacts', 'Disable artifact uploads (screenshots, videos, traces)')
    .option('--coverage', 'Enable code coverage collection')
    .allowUnknownOption()
    .allowExcessArguments()
    .action(async (options, command) => {
      // Update logger debug state based on CLI option
      if (options.debug) {
        logger.setDebug(true);
      }

      try {
        // Get remaining arguments (everything after 'test')
        const args = command.args || [];

        // Create and execute test command
        const testCommand = new TestCommand();
        const result = await testCommand.execute(options, args);

        // Exit with Playwright's exit code
        process.exit(result.exitCode);
      } catch (error) {
        if (error instanceof TestDinoError) {
          // Custom errors have well-formatted messages
          logger.error(error.message);
        } else {
          logger.error(
            error instanceof Error ? error.message : String(error),
            error instanceof Error ? error : undefined
          );
        }

        process.exit(1);
      }
    });

  return program;
}

/**
 * Main CLI entry point
 */
async function main(): Promise<void> {
  try {
    logger.banner(getVersion());

    const program = buildProgram();
    await program.parseAsync(process.argv);
  } catch (error) {
    if (error instanceof TestDinoError) {
      logger.error(error.message);
    } else {
      logger.error(error instanceof Error ? error.message : String(error), error instanceof Error ? error : undefined);
    }

    process.exit(1);
  }
}

// Run CLI
main().catch((error) => {
  logger.error('Unexpected error', error instanceof Error ? error : undefined);
  process.exit(1);
});
