/**
 * Custom error classes for TestDino CLI
 * Provides clear, actionable error messages with suggestions
 */

/**
 * Base class for all TestDino CLI errors
 */
export class TestDinoError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'TestDinoError';
    Error.captureStackTrace(this, this.constructor);
  }
}

/**
 * Error thrown when authentication token is missing
 */
export class TokenMissingError extends TestDinoError {
  constructor() {
    const message = `Token is required to run tests with TestDino

Provide token via:
  • CLI flag:    npx tdpw test --token <your-token>
  • Environment: export TESTDINO_TOKEN=<your-token>
  • Config file: Create testdino.config.ts with token

Get your token at: https://testdino.com/settings`;

    super(message);
    this.name = 'TokenMissingError';
  }
}

/**
 * Error thrown when config file has syntax errors
 */
export class ConfigSyntaxError extends TestDinoError {
  constructor(configPath: string, originalError: Error) {
    const message = `Failed to load ${configPath}

${originalError.message}

Fix the syntax error and try again.`;

    super(message);
    this.name = 'ConfigSyntaxError';
  }
}

/**
 * Error thrown when Playwright is not installed
 */
export class PlaywrightNotInstalledError extends TestDinoError {
  constructor() {
    const message = `Playwright is not installed

Install Playwright:
  npm install -D @playwright/test

Then run:
  npx playwright install`;

    super(message);
    this.name = 'PlaywrightNotInstalledError';
  }
}

/**
 * Error thrown when config file cannot be found
 */
export class ConfigNotFoundError extends TestDinoError {
  constructor(configPath: string) {
    const message = `Config file not found: ${configPath}

Make sure the file exists and is readable.`;

    super(message);
    this.name = 'ConfigNotFoundError';
  }
}

/**
 * Error thrown when server URL is invalid
 */
export class InvalidServerUrlError extends TestDinoError {
  constructor(url: string) {
    const message = `Invalid server URL: ${url}

Server URL must be a valid HTTP or HTTPS URL.

Examples:
  • https://api.testdino.com
  • https://api-v0.testdino.com
  • https://global.testdino.com`;

    super(message);
    this.name = 'InvalidServerUrlError';
  }
}

/**
 * Error thrown when Playwright execution fails
 */
export class PlaywrightExecutionError extends TestDinoError {
  constructor(exitCode: number, message?: string) {
    const errorMessage = message
      ? `Playwright execution failed: ${message}`
      : `Playwright execution failed with exit code ${exitCode}`;

    super(errorMessage);
    this.name = 'PlaywrightExecutionError';
  }
}

/**
 * Error thrown when permission is denied
 */
export class PermissionDeniedError extends TestDinoError {
  constructor(path: string) {
    const message = `Permission denied: ${path}

Check file permissions and try again.`;

    super(message);
    this.name = 'PermissionDeniedError';
  }
}
